def run(value_list):
    # Filter values for 2019
    defined_contribution_2019 = None
    defined_benefit_2019 = None

    for item in value_list:
        if item['category'] == 'Defined contribution schemes' and item['header1'] == '2019 € million':
            defined_contribution_2019 = item['number_value']
        if item['category'] == 'Defined benefit schemes' and item['header1'] == '2019 € million':
            defined_benefit_2019 = item['number_value']

    # Calculate average for 2019 (using previous year's value if available)
    defined_contribution_2019_avg = defined_contribution_2019
    if defined_contribution_2019 is None:
        for item in value_list:
            if item['category'] == 'Defined contribution schemes' and item['header1'] == '2018 € million':
                defined_contribution_2019_avg = (defined_contribution_2019 + item['number_value']) / 2
                break
    defined_benefit_2019_avg = defined_benefit_2019
    if defined_benefit_2019 is None:
        for item in value_list:
            if item['category'] == 'Defined benefit schemes' and item['header1'] == '2018 € million':
                defined_benefit_2019_avg = (defined_benefit_2019 + item['number_value']) / 2
                break

    # Calculate the difference
    difference = defined_contribution_2019_avg - defined_benefit_2019_avg

    return (round(difference, 2), 'million')

